import React, { useState, useEffect, useRef } from 'react';
import { GlassCard } from './ui/GlassCard';
import { Volume2, Zap, Radio, Sliders, Play, Disc } from 'lucide-react';

// --- Types ---
type PadType = 'kick' | 'snare' | 'hihat' | 'tom' | 'clap' | 'fx' | 'synth';

interface Pad {
  id: number;
  label: string;
  type: PadType;
  key: string;
  color: string;
  note?: number; // Frequency for synth
}

const PADS: Pad[] = [
  { id: 0, label: 'BD-808', type: 'kick', key: 'Q', color: '#FF5500' },
  { id: 1, label: 'SD-909', type: 'snare', key: 'W', color: '#FF9F43' },
  { id: 2, label: 'CH-RAW', type: 'hihat', key: 'E', color: '#FFCC00' },
  { id: 3, label: 'TM-LOW', type: 'tom', key: 'A', color: '#FF5500' },
  { id: 4, label: 'CP-DRY', type: 'clap', key: 'S', color: '#FF9F43' },
  { id: 5, label: 'FX-ZAP', type: 'fx', key: 'D', color: '#00D2D3' },
  { id: 6, label: 'SYN-C2', type: 'synth', key: 'U', color: '#7F5AF0', note: 130.81 },
  { id: 7, label: 'SYN-Eb2', type: 'synth', key: 'I', color: '#7F5AF0', note: 155.56 },
  { id: 8, label: 'SYN-F2', type: 'synth', key: 'O', color: '#7F5AF0', note: 174.61 },
  { id: 9, label: 'SYN-G2', type: 'synth', key: 'J', color: '#7F5AF0', note: 196.00 },
  { id: 10, label: 'SYN-Bb2', type: 'synth', key: 'K', color: '#7F5AF0', note: 233.08 },
  { id: 11, label: 'SYN-C3', type: 'synth', key: 'L', color: '#7F5AF0', note: 261.63 },
];

export const RhythmArchitect: React.FC = () => {
  const [activePad, setActivePad] = useState<number | null>(null);
  const [volume, setVolume] = useState(0.8);
  const [filterFreq, setFilterFreq] = useState(2000);
  const [isReady, setIsReady] = useState(false);

  const audioCtxRef = useRef<AudioContext | null>(null);
  const masterGainRef = useRef<GainNode | null>(null);
  const filterNodeRef = useRef<BiquadFilterNode | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // --- Audio Engine Initialization ---
  const initAudio = () => {
    if (audioCtxRef.current) return;

    const Ctx = window.AudioContext || (window as any).webkitAudioContext;
    const ctx = new Ctx();

    const master = ctx.createGain();
    const filter = ctx.createBiquadFilter();
    const analyser = ctx.createAnalyser();

    // Signal Chain: Input -> Filter -> Master -> Analyser -> Destination
    filter.type = 'lowpass';
    filter.frequency.value = filterFreq;
    filter.Q.value = 1;

    master.gain.value = volume;
    analyser.fftSize = 256;

    filter.connect(master);
    master.connect(analyser);
    analyser.connect(ctx.destination);

    audioCtxRef.current = ctx;
    masterGainRef.current = master;
    filterNodeRef.current = filter;
    analyserRef.current = analyser;
    setIsReady(true);
  };

  // --- Sound Synthesis ---
  const triggerSound = (pad: Pad) => {
    if (!audioCtxRef.current) initAudio();
    if (!audioCtxRef.current || !filterNodeRef.current) return;

    const ctx = audioCtxRef.current;
    const t = ctx.currentTime;
    const dest = filterNodeRef.current; // Connect all voices to filter

    setActivePad(pad.id);
    setTimeout(() => setActivePad(null), 150);

    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    switch (pad.type) {
      case 'kick':
        osc.frequency.setValueAtTime(150, t);
        osc.frequency.exponentialRampToValueAtTime(0.01, t + 0.5);
        gain.gain.setValueAtTime(1.0, t);
        gain.gain.exponentialRampToValueAtTime(0.01, t + 0.5);
        osc.connect(gain);
        break;

      case 'snare':
        // Tone
        osc.type = 'triangle';
        osc.frequency.setValueAtTime(250, t);
        gain.gain.setValueAtTime(0.5, t);
        gain.gain.exponentialRampToValueAtTime(0.01, t + 0.2);
        osc.connect(gain);

        // Noise
        const noiseBufferSize = ctx.sampleRate * 0.2; // 0.2s
        const buffer = ctx.createBuffer(1, noiseBufferSize, ctx.sampleRate);
        const data = buffer.getChannelData(0);
        for (let i = 0; i < noiseBufferSize; i++) {
          data[i] = Math.random() * 2 - 1;
        }
        const noise = ctx.createBufferSource();
        noise.buffer = buffer;
        const noiseGain = ctx.createGain();
        noiseGain.gain.setValueAtTime(0.4, t);
        noiseGain.gain.exponentialRampToValueAtTime(0.01, t + 0.2);
        noise.connect(noiseGain);
        noiseGain.connect(dest);
        noise.start(t);
        break;

      case 'hihat':
        // Highpass Noise
        const hatBuffer = ctx.createBuffer(1, ctx.sampleRate * 0.05, ctx.sampleRate);
        const hatData = hatBuffer.getChannelData(0);
        for (let i = 0; i < hatBuffer.length; i++) {
            hatData[i] = Math.random() * 2 - 1;
        }
        const hatSrc = ctx.createBufferSource();
        hatSrc.buffer = hatBuffer;

        const hatFilter = ctx.createBiquadFilter();
        hatFilter.type = 'highpass';
        hatFilter.frequency.value = 5000;

        const hatGain = ctx.createGain();
        hatGain.gain.setValueAtTime(0.3, t);
        hatGain.gain.exponentialRampToValueAtTime(0.01, t + 0.05);

        hatSrc.connect(hatFilter);
        hatFilter.connect(hatGain);
        hatGain.connect(dest);
        hatSrc.start(t);
        return; // Early return as we handled connection

      case 'tom':
        osc.frequency.setValueAtTime(100, t);
        osc.frequency.exponentialRampToValueAtTime(10, t + 0.5);
        gain.gain.setValueAtTime(0.8, t);
        gain.gain.exponentialRampToValueAtTime(0.01, t + 0.5);
        osc.connect(gain);
        break;

      case 'clap':
         // Simulated Clap using envelope modulation on noise
        const clapBuffer = ctx.createBuffer(1, ctx.sampleRate * 0.2, ctx.sampleRate);
        const clapData = clapBuffer.getChannelData(0);
        for (let i = 0; i < clapBuffer.length; i++) clapData[i] = Math.random() * 2 - 1;
        const clapSrc = ctx.createBufferSource();
        clapSrc.buffer = clapBuffer;
        const clapGain = ctx.createGain();
        clapGain.gain.setValueAtTime(0.5, t);
        clapGain.gain.exponentialRampToValueAtTime(0.01, t + 0.15);
        clapSrc.connect(clapGain);
        clapGain.connect(dest);
        clapSrc.start(t);
        return;

      case 'fx':
         osc.type = 'sawtooth';
         osc.frequency.setValueAtTime(1200, t);
         osc.frequency.exponentialRampToValueAtTime(100, t + 0.3);
         gain.gain.setValueAtTime(0.3, t);
         gain.gain.exponentialRampToValueAtTime(0.01, t + 0.3);
         osc.connect(gain);
         break;

      case 'synth':
        osc.type = 'sawtooth';
        // Detune effect by creating a second oscillator
        const osc2 = ctx.createOscillator();
        osc2.type = 'square';
        osc2.detune.value = 10;

        const freq = pad.note || 440;
        osc.frequency.setValueAtTime(freq, t);
        osc2.frequency.setValueAtTime(freq, t);

        const synthGain = ctx.createGain();
        synthGain.gain.setValueAtTime(0.15, t);
        synthGain.gain.linearRampToValueAtTime(0.1, t + 0.1);
        synthGain.gain.exponentialRampToValueAtTime(0.001, t + 1.5); // Long release

        osc.connect(synthGain);
        osc2.connect(synthGain);
        synthGain.connect(dest);

        osc.start(t);
        osc2.start(t);
        osc.stop(t + 1.5);
        osc2.stop(t + 1.5);
        return;
    }

    gain.connect(dest);
    osc.start(t);
    osc.stop(t + 0.5);
  };

  // --- Parameter Updates ---
  useEffect(() => {
    if (masterGainRef.current) masterGainRef.current.gain.setTargetAtTime(volume, audioCtxRef.current!.currentTime, 0.05);
  }, [volume]);

  useEffect(() => {
    if (filterNodeRef.current) filterNodeRef.current.frequency.setTargetAtTime(filterFreq, audioCtxRef.current!.currentTime, 0.05);
  }, [filterFreq]);

  // --- Keyboard Support ---
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        const key = e.key.toUpperCase();
        const pad = PADS.find(p => p.key === key);
        if (pad) triggerSound(pad);
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  // --- Visualizer Loop ---
  useEffect(() => {
    let animationId: number;
    const render = () => {
        const canvas = canvasRef.current;
        const analyser = analyserRef.current;
        if (!canvas || !analyser) {
            animationId = requestAnimationFrame(render);
            return;
        }

        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        const bufferLength = analyser.frequencyBinCount;
        const dataArray = new Uint8Array(bufferLength);
        analyser.getByteTimeDomainData(dataArray);

        // Fade effect
        ctx.fillStyle = 'rgba(0, 0, 0, 0.2)';
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        ctx.lineWidth = 2;
        ctx.strokeStyle = '#7F5AF0'; // Violet
        ctx.beginPath();

        const sliceWidth = canvas.width / bufferLength;
        let x = 0;

        for (let i = 0; i < bufferLength; i++) {
            const v = dataArray[i] / 128.0;
            const y = (v * canvas.height) / 2;

            if (i === 0) ctx.moveTo(x, y);
            else ctx.lineTo(x, y);

            x += sliceWidth;
        }

        ctx.lineTo(canvas.width, canvas.height / 2);

        // Add Glow
        ctx.shadowBlur = 10;
        ctx.shadowColor = '#7F5AF0';
        ctx.stroke();
        ctx.shadowBlur = 0;

        // Draw frequency bars at bottom
        analyser.getByteFrequencyData(dataArray);
        const barWidth = (canvas.width / bufferLength) * 2.5;
        let barX = 0;
        for(let i=0; i<bufferLength/2; i++) {
            const barHeight = (dataArray[i] / 255) * (canvas.height * 0.4);
            ctx.fillStyle = `rgba(255, 85, 0, ${dataArray[i]/255})`; // Orange
            ctx.fillRect(barX, canvas.height - barHeight, barWidth, barHeight);
            barX += barWidth + 1;
        }

        animationId = requestAnimationFrame(render);
    };
    render();
    return () => cancelAnimationFrame(animationId);
  }, []);

  return (
    <section className="py-32 relative overflow-hidden flex flex-col items-center justify-center">

       {/* Background */}
       <div className="absolute inset-0 z-0">
         <img 
            src="https://images.unsplash.com/photo-1598488035139-bdbb2231ce04?q=80&w=2070&auto=format&fit=crop" 
            alt="Studio Texture" 
            className="w-full h-full object-cover opacity-20 mix-blend-color-dodge grayscale"
         />
         <div className="absolute inset-0 bg-gradient-to-t from-black via-black/80 to-black" />
       </div>

       <div className="container mx-auto px-6 relative z-10">

          <div className="mb-12 text-center">
             <span className="text-secondary text-xs font-bold tracking-[0.2em] uppercase mb-4 block animate-pulse">
                System Active
             </span>
             <h2 className="font-display font-medium text-4xl md:text-5xl text-white mb-6">
                Rhythm <span className="text-transparent bg-clip-text bg-gradient-to-r from-primary to-purple-400">Architect.</span>
             </h2>
             <p className="text-white/60 max-w-lg mx-auto">
                Real-time Web Audio synthesis. Tap the pads or use your keyboard to construct the groove.
             </p>
          </div>

          <GlassCard className="max-w-5xl mx-auto p-1 bg-black/40 border-white/10 shadow-[0_0_80px_rgba(127,90,240,0.1)]">

             {/* Main Deck Layout */}
             <div className="grid lg:grid-cols-12 min-h-[500px] bg-[#0A0A0A] rounded-[22px] overflow-hidden">

                {/* Left: Controls & Visualizer (4 cols) */}
                <div className="lg:col-span-4 bg-[#0F0F0F] border-r border-white/5 p-8 flex flex-col relative">

                    {/* Header */}
                    <div className="flex items-center gap-2 mb-8 text-white/40">
                        <Radio size={16} className={isReady ? "text-green-500 animate-pulse" : ""} />
                        <span className="text-[10px] uppercase tracking-widest font-bold">Signal Path</span>
                    </div>

                    {/* Canvas Visualizer */}
                    <div className="h-32 w-full bg-black rounded-lg border border-white/10 mb-8 relative overflow-hidden shadow-inner">
                        <canvas ref={canvasRef} width={300} height={128} className="w-full h-full opacity-80" />
                        <div className="absolute inset-0 bg-[linear-gradient(transparent_1px,#000_1px)] bg-[size:100%_4px] opacity-20 pointer-events-none" />
                    </div>

                    {/* Global Knobs */}
                    <div className="space-y-8 mt-auto">
                        <div className="space-y-3">
                            <div className="flex justify-between text-xs font-bold text-white/60 uppercase tracking-widest">
                                <span className="flex items-center gap-2"><Sliders size={12}/> LP Filter</span>
                                <span className="text-primary">{filterFreq} Hz</span>
                            </div>
                            <input 
                                type="range" min="100" max="10000" step="100"
                                value={filterFreq}
                                onChange={(e) => setFilterFreq(Number(e.target.value))}
                                className="w-full h-1 bg-white/10 rounded-lg appearance-none cursor-pointer [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:w-4 [&::-webkit-slider-thumb]:h-4 [&::-webkit-slider-thumb]:bg-primary [&::-webkit-slider-thumb]:rounded-full [&::-webkit-slider-thumb]:shadow-[0_0_10px_#FF5500]"
                            />
                        </div>

                        <div className="space-y-3">
                            <div className="flex justify-between text-xs font-bold text-white/60 uppercase tracking-widest">
                                <span className="flex items-center gap-2"><Volume2 size={12}/> Master Gain</span>
                                <span className="text-secondary">{(volume * 100).toFixed(0)}%</span>
                            </div>
                            <input 
                                type="range" min="0" max="1" step="0.01"
                                value={volume}
                                onChange={(e) => setVolume(Number(e.target.value))}
                                className="w-full h-1 bg-white/10 rounded-lg appearance-none cursor-pointer [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:w-4 [&::-webkit-slider-thumb]:h-4 [&::-webkit-slider-thumb]:bg-secondary [&::-webkit-slider-thumb]:rounded-full"
                            />
                        </div>
                    </div>
                </div>

                {/* Right: The Pads (8 cols) */}
                <div className="lg:col-span-8 p-8 md:p-12 relative">

                    {!isReady && (
                        <div className="absolute inset-0 z-20 bg-black/80 backdrop-blur-sm flex items-center justify-center">
                            <button 
                                onClick={initAudio}
                                className="px-8 py-4 bg-primary text-black font-bold uppercase tracking-widest rounded-full hover:scale-105 transition-transform flex items-center gap-3 shadow-[0_0_30px_rgba(255,85,0,0.4)]"
                            >
                                <Play size={18} fill="black" /> Initialize System
                            </button>
                        </div>
                    )}

                    <div className="h-full flex flex-col">
                        <div className="flex justify-between items-center mb-6">
                            <h3 className="text-white font-display text-xl tracking-wide">Performance Grid</h3>
                            <div className="flex gap-2">
                                <div className="px-3 py-1 rounded bg-white/5 border border-white/10 text-[10px] text-white/50 uppercase tracking-wider">
                                    Bank A
                                </div>
                            </div>
                        </div>

                        {/* Pad Grid */}
                        <div className="grid grid-cols-3 md:grid-cols-4 gap-4 h-full">
                            {PADS.map((pad) => (
                                <button
                                    key={pad.id}
                                    onClick={() => triggerSound(pad)}
                                    className={`
                                        relative group rounded-xl border transition-all duration-100 flex flex-col justify-between p-4 overflow-hidden
                                        ${activePad === pad.id ? 'translate-y-1 scale-95' : 'hover:-translate-y-1 hover:border-white/30'}
                                    `}
                                    style={{
                                        backgroundColor: activePad === pad.id ? `${pad.color}30` : 'rgba(255,255,255,0.03)',
                                        borderColor: activePad === pad.id ? pad.color : 'rgba(255,255,255,0.08)',
                                        boxShadow: activePad === pad.id ? `0 0 30px ${pad.color}40` : 'none'
                                    }}
                                >
                                    {/* Top Indicator */}
                                    <div className="flex justify-between items-start w-full opacity-50 group-hover:opacity-100">
                                        <span className="text-[10px] font-mono text-white/60">{pad.id + 1}</span>
                                        <div className={`w-1.5 h-1.5 rounded-full transition-colors ${activePad === pad.id ? 'bg-white' : 'bg-white/10'}`} />
                                    </div>

                                    {/* Icon / Decor */}
                                    <div className="absolute center top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 opacity-0 group-hover:opacity-20 transition-opacity">
                                        {pad.type === 'synth' ? <Disc size={40} /> : <Zap size={40} />}
                                    </div>

                                    {/* Label */}
                                    <div className="mt-auto">
                                        <div className="text-xs font-bold text-white tracking-wider mb-1 group-hover:text-white transition-colors">{pad.label}</div>
                                        <div className="text-[10px] font-mono text-white/30 flex items-center gap-1">
                                            <span className="w-4 h-4 rounded border border-white/10 flex items-center justify-center text-[8px]">{pad.key}</span>
                                            {pad.type.toUpperCase()}
                                        </div>
                                    </div>

                                    {/* Active Flash Overlay */}
                                    <div 
                                        className={`absolute inset-0 bg-white/20 transition-opacity duration-100 pointer-events-none ${activePad === pad.id ? 'opacity-100' : 'opacity-0'}`} 
                                    />
                                </button>
                            ))}
                        </div>
                    </div>
                </div>

             </div>
          </GlassCard>
       </div>
    </section>
  );
};

