import React, { useState, useEffect } from 'react';
import { Menu, X, Waves } from 'lucide-react';
import { NavItem } from '../types';

interface NavbarProps {
  onNavigate: (page: string) => void;
  currentPage: string;
}

const NAV_ITEMS: NavItem[] = [
  { label: 'Spaces', href: '#studios' },
  { label: 'Works', href: '#music' },
  { label: 'Process', href: '#process' }, 
];

export const Navbar: React.FC<NavbarProps> = ({ onNavigate, currentPage }) => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleNavClick = (e: React.MouseEvent, href: string) => {
    e.preventDefault();
    if (currentPage !== 'home') {
      onNavigate('home');
      // Wait for home to render before scrolling
      setTimeout(() => {
        const id = href.replace('#', '');
        const element = document.getElementById(id);
        if (element) element.scrollIntoView({ behavior: 'smooth' });
      }, 100);
    } else {
      const id = href.replace('#', '');
      const element = document.getElementById(id);
      if (element) element.scrollIntoView({ behavior: 'smooth' });
    }
  };

  return (
    <>
      {/* 
        Floating Pill Navbar 
      */}
      <header 
        className={`
          fixed top-6 left-1/2 -translate-x-1/2 z-50 
          transition-all duration-500 ease-out
          ${isScrolled ? 'w-[90%] md:w-auto' : 'w-[90%] md:w-auto'}
        `}
      >
        <div 
          className={`
            px-6 py-3 md:px-8 md:py-3
            rounded-full 
            bg-black/40 backdrop-blur-xl 
            border border-white/10 
            shadow-[0_8px_32px_rgba(0,0,0,0.3)]
            flex items-center justify-between gap-8 md:gap-12
            transition-all duration-300
            ${isScrolled ? 'bg-black/60 shadow-[0_10px_40px_rgba(0,0,0,0.5)]' : ''}
          `}
        >

          {/* Logo (Compact) */}
          <div 
            className="flex items-center gap-2 cursor-pointer group" 
            onClick={() => {
                onNavigate('home');
                window.scrollTo({top: 0, behavior: 'smooth'});
            }}
          >
            <div className="relative">
                <Waves className="w-5 h-5 text-white group-hover:text-secondary transition-colors" />
                <div className="absolute inset-0 bg-white/20 blur-md rounded-full opacity-0 group-hover:opacity-100 transition-opacity" />
            </div>
            <span className="font-display font-bold text-sm tracking-[0.2em] text-white">AURA</span>
          </div>

          {/* Desktop Nav Links */}
          <nav className="hidden md:flex items-center gap-8">
            <button
                onClick={() => onNavigate('home')}
                className={`text-[10px] font-medium uppercase tracking-[0.2em] transition-colors ${currentPage === 'home' ? 'text-white' : 'text-white/60 hover:text-white'}`}
            >
                Home
            </button>

            {/* Gallery Link (New Page) */}
            <button
                onClick={() => onNavigate('gallery')}
                className={`text-[10px] font-medium uppercase tracking-[0.2em] transition-colors ${currentPage === 'gallery' ? 'text-primary' : 'text-white/60 hover:text-white'}`}
            >
                Gallery
            </button>

            {NAV_ITEMS.map((item) => (
              <a 
                key={item.label}
                href={item.href}
                onClick={(e) => handleNavClick(e, item.href)}
                className="text-[10px] font-medium uppercase tracking-[0.2em] text-white/60 hover:text-white transition-colors"
              >
                {item.label}
              </a>
            ))}
          </nav>

          {/* CTA (Small) */}
          <div className="hidden md:block">
            <button 
                onClick={() => {
                    if (currentPage !== 'home') onNavigate('home');
                    setTimeout(() => document.getElementById('booking')?.scrollIntoView({ behavior: 'smooth'}), 100);
                }}
                className="
                    px-4 py-1.5 rounded-full 
                    bg-white text-black 
                    text-[10px] font-bold uppercase tracking-wider 
                    hover:bg-secondary hover:text-black transition-colors
                    shadow-[0_0_15px_rgba(255,255,255,0.1)]
                "
            >
                Book
            </button>
          </div>

          {/* Mobile Toggle */}
          <button 
            className="md:hidden text-white/80 hover:text-white"
            onClick={() => setMobileMenuOpen(true)}
          >
            <Menu size={20} />
          </button>

        </div>
      </header>

      {/* Mobile Menu Overlay */}
      {mobileMenuOpen && (
        <div className="fixed inset-0 bg-black/95 backdrop-blur-3xl z-[60] flex flex-col items-center justify-center animate-in fade-in duration-200">
          <button 
            className="absolute top-8 right-8 text-white/60 hover:text-white"
            onClick={() => setMobileMenuOpen(false)}
          >
            <X size={32} />
          </button>

          <nav className="flex flex-col items-center gap-8">
             <button 
                onClick={() => { onNavigate('home'); setMobileMenuOpen(false); }}
                className="text-3xl font-display font-light text-white"
             >
                Home
             </button>
             <button 
                onClick={() => { onNavigate('gallery'); setMobileMenuOpen(false); }}
                className="text-3xl font-display font-light text-primary"
             >
                Gallery
             </button>

            {NAV_ITEMS.map((item) => (
              <a 
                key={item.label}
                href={item.href}
                className="text-3xl font-display font-light text-white"
                onClick={(e) => {
                    setMobileMenuOpen(false);
                    handleNavClick(e, item.href);
                }}
              >
                {item.label}
              </a>
            ))}
             <button 
                onClick={() => {
                 setMobileMenuOpen(false);
                 if (currentPage !== 'home') onNavigate('home');
                 setTimeout(() => document.getElementById('booking')?.scrollIntoView({ behavior: 'smooth'}), 100);
               }}
                className="mt-8 px-8 py-3 rounded-full bg-white text-black text-xs font-bold uppercase tracking-widest"
            >
                Book Session
            </button>
          </nav>
        </div>
      )}
    </>
  );
};

